class Solution {
    private static final int MOD = (int) 1e9 + 7;
    public int numberOfStableArrays(int zero, int one, int limit) {
        int[][][] dp = new int[zero + 1][one + 1][limit + 1];
        dp[0][0][0] = 1;
        for (int i = 0; i <= zero; i++) {
            for (int j = 0; j <= one; j++) {
                for (int k = 0; k <= limit; k++) {
                    if (i < zero) {
                        dp[i + 1][j][Math.min(limit, k + 1)] = (dp[i + 1][j][Math.min(limit, k + 1)] + dp[i][j][k]) % MOD;
                    }
                    if (j < one && k < limit) {
                        dp[i][j + 1][1] = (dp[i][j + 1][1] + dp[i][j][k]) % MOD;
                    }
                }
            }
        }
        int res = 0;
        for (int k = 0; k <= limit; k++) {
            res = (res + dp[zero][one][k]) % MOD;
        }
        return res;
    }
}
